fun solve(prices: Array<Long>, strategy: Array<Long>, k: Long): Long {
    val n = prices.size
    var originalProfit = 0L
    for (i in 0 until n) {
        originalProfit += strategy[i] * prices[i]
    }

    val prefixSum = LongArray(n + 1)
    for (i in 0 until n) {
        prefixSum[i + 1] = prefixSum[i] + prices[i]
    }

    val windowSize = k.toInt()
    var windowSum = 0L
    for (i in 0 until windowSize) {
        windowSum += strategy[i] * prices[i]
    }

    var maxDelta = -Long.MAX_VALUE
    val halfK = k / 2

    for (i in 0..(n - windowSize)) {
        val start = i + halfK
        val end = i + windowSize - 1
        val sumSecondHalf = prefixSum[end + 1] - prefixSum[start]
        val delta = sumSecondHalf - windowSum
        maxDelta = max(maxDelta, delta)

        if (i < n - windowSize) {
            windowSum -= strategy[i] * prices[i]
            windowSum += strategy[i + windowSize] * prices[i + windowSize]
        }
    }

    return originalProfit + max(0L, maxDelta)
}
