function solve(prices: number[], strategy: number[], k: number): number {
    const n = prices.length;
    let originalProfit = 0;
    for (let i = 0; i < n; i++) {
        originalProfit += strategy[i] * prices[i];
    }

    // Compute prefix sum of prices
    const prefixSum = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefixSum[i + 1] = prefixSum[i] + prices[i];
    }

    // Compute sliding window sum of strategy * prices
    let windowSum = 0;
    for (let i = 0; i < k; i++) {
        windowSum += strategy[i] * prices[i];
    }

    let maxDelta = -Infinity;

    for (let i = 0; i <= n - k; i++) {
        // Calculate sum_second_half for this window
        const secondHalfStart = i + k / 2;
        const secondHalfEnd = i + k - 1;
        const sumSecondHalf = prefixSum[secondHalfEnd + 1] - prefixSum[secondHalfStart];

        const delta = sumSecondHalf - windowSum;
        maxDelta = Math.max(maxDelta, delta);

        // Slide the window
        if (i < n - k) {
            // Remove the element leaving the window (i)
            windowSum -= strategy[i] * prices[i];
            // Add the new element entering (i + k)
            windowSum += strategy[i + k] * prices[i + k];
        }
